#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#define PI 3.14159265358979323846
#define EPS 1e-9

// Structure to represent a point
typedef struct {
    int x, y;
} Point;

// Function to calculate the orientation of three points
int orientation(Point p, Point q, Point r) {
    int val = (q.y - p.y) * (r.x - q.x) - (q.x - p.x) * (r.y - q.y);
    if (val == 0) return 0; // Collinear
    return (val > 0) ? 1 : 2; // Clockwise or counterclockwise
}

// Function to calculate the convex hull using Graham Scan
void convexHull(Point points[], int n, Point hull[]) {
    int l = 0;
    for (int i = 1; i < n; i++) {
        if (points[i].x < points[l].x) l = i;
    }
    int p = l, q;
    do {
        hull[p] = points[l];
        q = (p + 1) % n;
        for (int i = 0; i < n; i++) {
            if (orientation(points[l], points[i], points[q]) == 2) q = i;
        }
        l = q;
        p = (p + 1) % n;
    } while (p != 0);
}

// Function to calculate the area of a polygon using the Shoelace formula
double polygonArea(Point points[], int n) {
    double area = 0.0;
    for (int i = 0; i < n; i++) {
        int j = (i + 1) % n;
        area += points[i].x * points[j].y;
        area -= points[j].x * points[i].y;
    }
    area = fabs(area) / 2.0;
    return area;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        Point points[n];
        for (int i = 0; i < n; i++) {
            scanf("%d %d", &points[i].x, &points[i].y);
        }
        Point hull[n];
        convexHull(points, n, hull);
        double area = polygonArea(hull, n);
        printf("%d\n", (int)round(2 * area));
    }
    return 0;
}

