import java.util.Scanner;
import java.util.ArrayList;
import java.lang.Math;

public class Main {
    static class Point {
        int x, y;
        Point(int x, int y) {
            this.x = x;
            this.y = y;
        }
    }

    public static int orientation(Point p, Point q, Point r) {
        int val = (q.y - p.y) * (r.x - q.x) - (q.x - p.x) * (r.y - q.y);
        if (val == 0) return 0; // Collinear
        return (val > 0) ? 1 : 2; // Clockwise or counterclockwise
    }

    public static ArrayList<Point> convexHull(Point[] points) {
        int n = points.length;
        int l = 0;
        for (int i = 1; i < n; i++) {
            if (points[i].x < points[l].x) l = i;
        }
        int p = l, q;
        ArrayList<Point> hull = new ArrayList<>();
        do {
            hull.add(points[l]);
            q = (p + 1) % n;
            for (int i = 0; i < n; i++) {
                if (orientation(points[l], points[i], points[q]) == 2) q = i;
            }
            l = q;
            p = (p + 1) % n;
        } while (p != 0);
        return hull;
    }

    public static double polygonArea(ArrayList<Point> points) {
        double area = 0.0;
        for (int i = 0; i < points.size(); i++) {
            int j = (i + 1) % points.size();
            area += points.get(i).x * points.get(j).y;
            area -= points.get(j).x * points.get(i).y;
        }
        area = Math.abs(area) / 2.0;
        return area;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            int n = sc.nextInt();
            Point[] points = new Point[n];
            for (int i = 0; i < n; i++) {
                points[i] = new Point(sc.nextInt(), sc.nextInt());
            }
            ArrayList<Point> hull = convexHull(points);
            double area = polygonArea(hull);
            System.out.println((int) Math.round(2 * area));
        }
    }
}

